mapper.select:
/* , '\n가격: ', MIN(D.SALES_PRICE), '원' , '\n할인율: ', MIN(D.SALES_RATE), '%' */ SELECT M.SPECIAL_ID AS ID ,M.SPECIAL_NM , CONCAT( '🛍 ', M.SPECIAL_NM, ': ', MIN(P.PRODUCT_NM) , CASE WHEN COUNT(D.SPECIAL_DTL_ID) > 1 THEN CONCAT(' 외 ', COUNT(D.SPECIAL_DTL_ID) - 1, '건') ELSE '' END ) AS TITLE , M.START_DATE AS START , M.END_DATE AS END , '#fbbf24' AS BACKGROUND_COLOR , M.PROGRESS_TYPE FROM special_mst M JOIN special_dtl D ON M.SPECIAL_ID = D.SPECIAL_ID JOIN product_mst P ON D.PRODUCT_ID = P.PRODUCT_ID WHERE 1=1 AND M.LOCATION_ID = #{locationId}
AND M.START_DATE <= STR_TO_DATE(CONCAT(#{endDate} ,' 23:59:59'), '%Y-%m-%d %H:%i:%s') /* 특가 시작일이 조회 종료일보다 빠르거나 같아야 함*/ AND M.END_DATE >= STR_TO_DATE(CONCAT(#{startDate},' 00:00:00'), '%Y-%m-%d %H:%i:%s') /* 특가 종료일이 조회 시작일보다 늦거나 같아야 함 */
GROUP BY M.SPECIAL_ID

SELECT SRM.USER_ID ,SRM.SPECIAL_RSV_MST_ID , UM.NAME , UM.PHONE , #{locationId} LOCATION_ID
, MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SRD.RESERVATION_CNT ELSE 0 END) AS ${col} , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SRM.SPECIAL_RSV_MST_ID ELSE 0 END) AS SPECIAL_RSV_MST_ID_${col} , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SRD.SPECIAL_RSV_DTL_ID ELSE 0 END) AS SPECIAL_RSV_DTL_ID_${col} , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SRD.SPECIAL_DTL_ID ELSE 0 END) AS SPECIAL_DTL_ID_${col} , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SM.SPECIAL_ID ELSE 0 END) AS SPECIAL_MST_ID_${col} , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SD.SALES_PRICE ELSE 0 END) AS SPECIAL_PRICE_${col} /** 2025 10 31 추가 예약가능 총수량 , 남은수량 */ , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SD.QTY ELSE 0 END) AS SPECIAL_TOT_QTY_${col} , MAX(CASE WHEN SD.SPECIAL_DTL_ID = CAST(REPLACE('${col}', 'PRODUCT_', '') AS UNSIGNED) THEN SD.REMAIN_QTY ELSE 0 END) AS SPECIAL_REMAIN_QTY_${col}
, SUM(SRD.RESERVATION_PRICE) AS RESERVATION_PRICE , SUM(SRD.SALES_PRICE ) AS SALES_PRICE , MIN(SRM.RESERVATION_STATUS) AS RESERVATION_STATUS , MAX(UM.GENDER) AS GENDER , MAX(UM.AGE) AS AGE , MAX(SRM.DESCRIPTION) AS DESCRIPTION , MAX( CASE WHEN SRM.UPDATE_USER IS NULL THEN SRM.CREATE_USER ELSE SRM.UPDATE_USER END) UPDATE_USER FROM special_rsv_mst SRM JOIN special_rsv_dtl SRD ON SRM.SPECIAL_RSV_MST_ID = SRD.SPECIAL_RSV_MST_ID JOIN special_dtl SD ON SRD.SPECIAL_DTL_ID = SD.SPECIAL_DTL_ID JOIN special_mst SM ON SD.SPECIAL_ID = SM.SPECIAL_ID LEFT JOIN user_mst UM ON SRM.USER_ID = UM.USER_ID WHERE 1=1 AND SM.STORE_ID = #{storeId} AND SM.LOCATION_ID = #{locationId}
AND SD.SPECIAL_ID = #{specialId}
AND SM.START_DATE <= STR_TO_DATE(CONCAT(#{startDate},' 23:59:59'), '%Y-%m-%d %H:%i:%s') AND SM.START_DATE >= STR_TO_DATE(CONCAT(#{startDate},' 00:00:00'), '%Y-%m-%d %H:%i:%s')
GROUP BY SRM.USER_ID ,SRM.SPECIAL_RSV_MST_ID ORDER BY (CASE WHEN SRM.RESERVATION_STATUS = 'RESERVATION' THEN 0 ELSE 1 END) , SRM.SPECIAL_RSV_MST_ID DESC

/* 특가 상품 예약 리스트 동적 컬럼 */ SELECT SM.SPECIAL_ID , CONCAT('PRODUCT_',SD.SPECIAL_DTL_ID) SPECIAL_DTL_ID , SM.SPECIAL_NM , PM.PRODUCT_NM , SD.SALES_PRICE , SD.QTY TOT_QTY , CASE WHEN SD.REMAIN_QTY IS NULL THEN SD.QTY ELSE SD.REMAIN_QTY END REMAIN_QTY FROM special_mst SM JOIN special_dtl SD ON SM.SPECIAL_ID = SD.SPECIAL_ID JOIN product_mst PM ON SD.PRODUCT_ID = PM.PRODUCT_ID WHERE 1=1 AND SM.STORE_ID = #{storeId} AND SM.LOCATION_ID = #{locationId}
AND SM.START_DATE <= STR_TO_DATE(CONCAT(#{startDate},' 23:59:59'), '%Y-%m-%d %H:%i:%s') AND SM.START_DATE >= STR_TO_DATE(CONCAT(#{startDate},' 00:00:00'), '%Y-%m-%d %H:%i:%s')
AND SM.SPECIAL_ID = #{specialId}
ORDER BY SM.START_DATE , SM.SPECIAL_ID

SELECT SRM.SPECIAL_RSV_MST_ID AS REF_ID , SRD.SPECIAL_RSV_DTL_ID AS RSV_DTL_ID , SM.SPECIAL_ID AS BIZ_ID , SM.SPECIAL_NM AS TITLE , SD.PRODUCT_ID AS PRODUCT_ID , P.PRODUCT_NM AS PRODUCT_NM , 1 AS PRODUCT_CNT , SRD.RESERVATION_CNT AS QTY , SD.SALES_PRICE AS UNIT_PRICE , (SRD.RESERVATION_CNT * SD.SALES_PRICE) AS AMOUNT , SRM.RESERVATION_STATUS AS STATUS , CASE WHEN COALESCE(SRD.SALES_CNT,0) >= SRD.RESERVATION_CNT THEN 1 ELSE 0 END AS COMPLETED , DATE_FORMAT(SM.START_DATE, '%Y-%m-%d %H:%i') AS PICKUP_START_DATE , DATE_FORMAT(SM.PICKUP_END_DATE, '%Y-%m-%d %H:%i') AS PICKUP_END_DATE
/* DB system_time_zone=UTC 이고 START_DATE/PICKUP_END_DATE 는 KST 벽시계로 저장됨 → NOW()(UTC) 대신 KST now(UTC_TIMESTAMP()+9h)로 비교해야 픽업 가능/만료 판정이 맞다 */ , CASE WHEN (UTC_TIMESTAMP() + INTERVAL 9 HOUR) >= SM.START_DATE AND (SM.PICKUP_END_DATE IS NULL OR (UTC_TIMESTAMP() + INTERVAL 9 HOUR) <= SM.PICKUP_END_DATE) THEN 1 ELSE 0 END AS PICKUPABLE , CASE WHEN SM.PICKUP_END_DATE IS NOT NULL AND (UTC_TIMESTAMP() + INTERVAL 9 HOUR) > SM.PICKUP_END_DATE THEN 1 ELSE 0 END AS EXPIRED
FROM special_rsv_mst SRM JOIN special_rsv_dtl SRD ON SRM.SPECIAL_RSV_MST_ID = SRD.SPECIAL_RSV_MST_ID AND SRD.CANCEL_YN = 'N' JOIN special_dtl SD ON SRD.SPECIAL_DTL_ID = SD.SPECIAL_DTL_ID JOIN special_mst SM ON SD.SPECIAL_ID = SM.SPECIAL_ID LEFT JOIN product_mst P ON SD.PRODUCT_ID = P.PRODUCT_ID WHERE SRM.USER_ID = #{userId} AND SM.STORE_ID = #{storeId} AND SM.LOCATION_ID = #{locationId} AND SRM.RESERVATION_STATUS IN ('RESERVATION','COMPLETE') AND SRD.RESERVATION_CNT > 0 ORDER BY PICKUPABLE DESC, SM.START_DATE ASC, SRM.SPECIAL_RSV_MST_ID ASC, SRD.SPECIAL_RSV_DTL_ID ASC
